import{_ as a,o as e,c as b,j as r,a as t,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"红嫁衣","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/红嫁衣.md","filePath":"4.资源分区/7.物品与装备/6.套装/红嫁衣.md"}'),n={name:"4.资源分区/7.物品与装备/6.套装/红嫁衣.md"};function o(d,p,l,_,i,c){return e(),b("div",null,[...p[0]||(p[0]=[r("h1",{id:"红嫁衣",tabindex:"-1"},[t("红嫁衣 "),r("a",{class:"header-anchor",href:"#红嫁衣","aria-label":'Permalink to "红嫁衣"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),s('<h1 id="红嫁衣-1" tabindex="-1">红嫁衣 <a class="header-anchor" href="#红嫁衣-1" aria-label="Permalink to &quot;红嫁衣&quot;">​</a></h1><p>红嫁衣<br> 古时，民间旧俗新娘的传统嫁衣是：凤冠霞帔云肩，脸遮红方巾，颈套项圈天官锁，胸挂照妖镜，手臂缠“定手银”；下身着红裙、红裤、红缎绣花鞋，千娇百媚，一身红色，制洋洋。<br> 注1：全文中的植⒉皇谴肀鹱帧<br> 注2：该资源必须按顺序购买，即嫁衣，方巾，绣鞋等等。</p><p>嫁衣·壹<br> 分类：奇物<br> 位置：斗篷位<br> 价格：C+1000<br> 描述：“桃花好，朱颜巧，凤袍霞帔鸳鸯袄。”<br> 富贵花卉，凤凰朝阳，金银点缀的红色长尾鸾袍，飘带披帛，尽是一身红嫁衣。<br> 嫁衣：这是一身女子出嫁时的衣裳，尽显雍容华美，极少数人会选择打破这份智斓姆瘴А<br> 红嫁衣会为穿戴者提供5点闪避防御的提升。</p><p>由于新婚之郑所有初次见到你且好感不低于冷漠态度的单位都将提升1级，最高不会高于友善，但如果初始是友善态度的单位，初始好感会“不知为何”的降低1级，不会因此低于冷漠，并因为感到毛骨悚然而获得只存在一轮的1点恐惧不良点数。</p><p>忌讳：“离漂亮的女人远点，特别是穿红衣服的漂亮女人。”<br> 穿戴者在受到伤害时，造成伤害的单位会“不知为何”的承受1点不可豁免的恐惧不良点数，这个效果基于穿戴者的闪避防御。</p><p>方巾·贰<br> 分类：奇物<br> 位置：面具位<br> 价格：C+1000<br> 描述：“赊天一片霞，裁作盖头纱。醉在红绸后，含羞看烛花。”<br> 五尺见方的绸缎，四角饰缀铜钱，自然下垂盖住整个面部。<br> 五尺绸：这是一块绵软黏腻的绸缎，外观嫣红，是女子出嫁时用于盖住头部的物品。<br> 红方巾会为穿戴者提供5点外貌的提升，同时穿戴嫁衣时间，嫁衣提供的防御将增加2点。</p><p>由于新婚之郑所有初次见到你且好感不低于冷漠态度的单位都将提升1级，最高不会高于友善，但如果初始是友善态度的单位，初始好感会“不知为何”的降低1级，不会因此低于冷漠，并因为感到毛骨悚然而获得只存在一轮的1点恐惧不良点数。</p><p>这个效果与嫁衣提供的态度提升/降低叠加计算，恐惧点数也会叠加，但不会使其陷入严重或毁灭性后果。</p><p>盖头：“相信我，你不会喜欢盖头下那副模样的，因此你最好不要掀开它。”<br> 同时穿戴嫁衣时，嫁衣提供的为攻击者造成恐惧不良点数的效果提升1点计算。此外，穿戴者可以正常接触灵体或虚体，反之亦然，就好像是具有全身【法破】一样处理。</p><p>绣鞋·叁<br> 分类：奇物<br> 位置：鞋袜位<br> 价格：C+1000<br> 描述：“鸳鸯织就欲双飞，一凤一凰贺新婚。”<br> 里衬白地印花布，鞋面为红缎，前后缝合。<br> 绣鞋：小巧的绣花鞋，新婚智斓拇┐髌贰<br> 绣鞋会为穿戴者提供内在最高支线等级*10米的基础移动速度提升，同时增加嫁衣提供的防御3点。</p><p>由于新婚之郑所有初次见到你且好感不低于冷漠态度的单位都将提升1级，最高不会高于友善，但如果初始是友善态度的单位，初始好感会“不知为何”的降低1级，不会因此低于冷漠，并因为感到毛骨悚然而获得只存在一轮的1点恐惧不良点数。</p><p>这个效果与嫁衣/方巾提供的态度提升/降低叠加计算，恐惧点数也会叠加，但不会使其陷入严重或毁灭性后果。</p><p>殷红：“请不要细究这上面的殷红色调，也不要好奇手感为何黏腻，这对大家都好。”<br> 同时穿戴嫁衣/方巾时，嫁衣/方巾提供的为攻击者造成恐惧不良点数的效果将总计提升1点计算，即此时合计造成3点。</p><p>起棺·肆<br> 分类：奇物<br> 价格：C+1000<br> 描述：横看成棺竖成轿，官人亦喜亦悲凉。 红烛长明唢呐响，棺中新人朱唇翘。</p><p>郑旱ス摹⒌ズ拧⒌ミ锬糯底嗲耙，纸人抬纸轿，纸轿亦纸棺。<br> 若你单独乘坐任何载具，则对应载具外观改为八抬大轿，金灯执事，然而轿是纸轿，前方有唢呐为引，红烛长明。</p><p>现在，只要初始不是极端负面态度，那么计算嫁衣/方巾/绣鞋带来的态度提升时，就能正常提升态度等级，且起棺会额外再提升1次态度，上限依旧是友善。</p><p>丧：<br> 同时穿戴嫁衣/方巾/绣鞋时，嫁衣/方巾/绣鞋提供的为攻击者造成恐惧不良点数的效果将总计提升1点计算，即此时合计造成4点。<br> 在计算这4点恐惧时，对方每承受1点恐惧不良点数，就使对方在攻击你的检定中承受2DP的士气减值，即使这是一个范围攻击。</p><p>【贰件套】：穿戴者不会受到纯物理类型的伤害，也不会被普通的物理行为影响。但是如【能量】、【法破】、【力场】等特性的行为都可以影响或伤害到穿戴者。<br> 【肆件套】：在贰件套的基础上，你可以正常影响虚体，你不会被闻到，听到，可以半速飞行，可以无阻拦穿透普通的固体、液体、气体等，但是如过深的地底会具有类似【立场】的特性、腐蚀性液体或气体会有类似【能量】的特性，在遇上这些情况时会无法穿透或是受伤穿透。</p><p>下属载具<br> 纸轿<br> 价格：250<br> 移动速度：60米/轮<br> 防御面：4<br> 结构值：16<br> 纸轿视为一种轻型载具，操纵检定使用器用：轻型载具。你可以在购买时额外支付750分使纸轿的纸人具有自主行动能力，但即使如此，纸轿依旧只能进行移动，且受到的火焰伤害翻倍计算。</p><p>纸人：纸轿在水或下雨的场景中将无法使用，因为水会把纸泡软。<br> 计算属性时，纸轿如同物品一样不具有属性，也不能为承载的单位提供任何遮蔽效果。</p><p>注：如果阅读本资源时出现了异常描述，请不要反馈，因为一切正常。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',23)])])}const f=a(n,[["render",o]]);export{m as __pageData,f as default};
